extension Date {
    func formatted(date: Date.FormatStyle.DateStyle = .complete, time: Date.FormatStyle.TimeStyle = .complete) -> String {
        let formatter = DateFormatter()
        formatter.dateStyle = date
        formatter.timeStyle = time
        return formatter.string(from: self)
    }
}

